#include <iostream>
#include <string>
#include <vector>

int main()
{
    int argc{};
    std::cin >> argc;
    std::cin.ignore();

    std::vector<std::string> argv(argc);
    for (int i{ 0 }; i < argc; ++i)
        std::getline(std::cin, argv[i]);

    if (argc <= 1)
    {
        std::cout << "No names provided." << '\n';
        return 0;
    }

    for (int i{ 1 }; i < argc; ++i)
        std::cout << "Hello, " << argv[i] << "!" << '\n';

    return 0;
}

