solution_code:
#include <iostream>
#include <string>
#include <vector>

int main()
{
    int argc{};
    std::cin >> argc;
    std::cin.ignore();

    std::vector<std::string> argv(argc);
    for (int i{ 0 }; i < argc; ++i)
        std::getline(std::cin, argv[i]);

    int sum{ 0 };
    int max{ 0 };
    bool first{ true };
    for (int i{ 1 }; i < argc; ++i)
    {
        int value{ std::stoi(argv[i]) };
        sum += value;
        if (first || value > max)
        {
            max = value;
            first = false;
        }
    }

    std::cout << "Sum: " << sum << '\n';
    std::cout << "Max: " << max << '\n';

    return 0;
}
